# Create a Conditional Access policy requiring MFA on mobile devices:
az rest \
  --method POST \
  --uri "https://graph.microsoft.com/v1.0/identity/conditionalAccess/policies" \
  --body '{
    "displayName": "Require MFA for Azure mobile app",
    "state": "enabled",
    "conditions": {
      "platforms": {
        "includePlatforms": ["android", "iOS"]
      },
      "applications": {
        "includeApplications": ["797f4846-ba00-4fd7-ba43-dac1f8f63013"]
      },
      "users": {
        "includeGroups": ["all-users-group-id"]
      }
    },
    "grantControls": {
      "operator": "AND",
      "builtInControls": ["mfa"]
    }
  }' \
  --headers "Content-Type=application/json"
